 39	  const { t } = useTranslation('plugin__kuadrant-console-plugin');
 40	  const [createView, setCreateView] = React.useState<'form' | 'yaml'>('form');
 41	  const [policyName, setPolicyName] = React.useState('');
 42	  const [selectedNamespace] = useActiveNamespace();
 43	  const [selectedGateway, setSelectedGateway] = React.useState<Gateway>({
 44	    name: '',
 45	    namespace: '',
 46	  });
 47	  const [loadBalancing, setLoadBalancing] = React.useState<LoadBalancing>({
 48	    geo: '',
 49	    weight: null,
 50	    defaultGeo: '',
 51	  });
 52	  const [healthCheck, setHealthCheck] = React.useState<HealthCheck>({
 53	    endpoint: '',
 54	    failureThreshold: null,
 55	    port: null,
 56	    protocol: '',
 57	  });
 58	  const [providerRefs, setProviderRefs] = React.useState([]);
 59	  const [creationTimestamp, setCreationTimestamp] = React.useState('');
 60	  const [resourceVersion, setResourceVersion] = React.useState('');
 61	  const location = useLocation();
 62	  const pathSplit = location.pathname.split('/');
 63	  const nameEdit = pathSplit[6];
 64	  const namespaceEdit = pathSplit[3];
 65	  const [formDisabled, setFormDisabled] = React.useState(false);
 66	  const [create, setCreate] = React.useState(true);
 67	  const [loadBalancingExpanded, setLoadBalancingExpanded] = React.useState(false);
 68	  const [healthExpanded, setHealthExpanded] = React.useState(false);
 69	
 70	  let isFormValid = false;
 71	
 72	  const createDNSPolicy = () => {
 73	    const hasHealthCheck =
 74	      healthCheck.endpoint ||
 75	      healthCheck.failureThreshold ||
 76	      healthCheck.port ||
 77	      healthCheck.protocol != '';
 78	
 79	    const hasLoadBalancing =
 80	      loadBalancing.geo || loadBalancing.defaultGeo != '' || loadBalancing.weight;
 81	
 82	    return {
 83	      apiVersion:
 84	        resourceGVKMapping['DNSPolicy'].group + '/' + resourceGVKMapping['DNSPolicy'].version,
 85	      kind: resourceGVKMapping['DNSPolicy'].kind,
 86	      metadata: {
 87	        name: policyName,
 88	        namespace: selectedNamespace,
 89	        ...(creationTimestamp ? { creationTimestamp } : {}),
 90	        ...(resourceVersion ? { resourceVersion } : {}),
 91	      },
 92	      spec: {
 93	        targetRef: {
 94	          group: 'gateway.networking.k8s.io',
 95	          kind: 'Gateway',
 96	          name: selectedGateway.name,
 97	        },
 98	        providerRefs: providerRefs.length > 0 ? [providerRefs[0]] : [],
 99	        ...(hasLoadBalancing
100	          ? {
101	              loadBalancing: {
102	                ...(loadBalancing?.weight ? { weight: loadBalancing.weight } : {}),
103	                ...(loadBalancing?.geo ? { geo: loadBalancing.geo } : {}),
104	                ...(loadBalancing.defaultGeo !== ''
105	                  ? { defaultGeo: loadBalancing.defaultGeo }
106	                  : {}),
107	              },
108	            }
109	          : {}),
110	        ...(hasHealthCheck
111	          ? {
112	              healthCheck: {
113	                ...(healthCheck?.endpoint ? { endpoint: healthCheck.endpoint } : {}),
114	                ...(healthCheck?.failureThreshold
115	                  ? { failureThreshold: healthCheck.failureThreshold }
116	                  : {}),
117	                ...(healthCheck?.port ? { port: healthCheck.port } : {}),
118	                ...(healthCheck?.protocol ? { protocol: healthCheck.protocol } : {}),
119	              },
120	            }
121	          : {}),
122	      },
123	    };
124	  };
125	
126	  const [yamlInput, setYamlInput] = React.useState(createDNSPolicy);
127	  const dnsPolicy = createDNSPolicy();
128	  const dnsPolicyGVK = getGroupVersionKindForResource({
129	    apiVersion: `${resourceGVKMapping['DNSPolicy'].group}/${resourceGVKMapping['DNSPolicy'].version}`,
130	    kind: resourceGVKMapping['DNSPolicy'].kind,
131	  });
132	  const [dnsPolicyModel] = useK8sModel({
133	    group: dnsPolicyGVK.group,
134	    version: dnsPolicyGVK.version,
135	    kind: dnsPolicyGVK.kind,
136	  });
137	
138	  const history = useHistory();
139	
140	  interface dnsPolicyEdit extends K8sResourceCommon {
141	    spec?: {
142	      targetRef?: {
143	        group?: string;
144	        kind?: string;
145	        name?: string;
146	      };
147	
148	      loadBalancing: {
149	        weight?: number;
150	        geo?: string;
151	        defaultGeo?: boolean;
152	      };
153	      providerRefs?: {
154	        name?: string;
155	      }[];
156	
157	      healthCheck?: {
158	        endpoint?: string;
159	        failureThreshold?: number;
160	        port?: number;
161	        protocol?: 'HTTP' | 'HTTPS';
162	      };
163	    };
164	  }
165	
166	  //Checking if the policy already exists and is to be edited or if its new and is being created
167	  let dnsResource = null;
168	  if (nameEdit) {
169	    dnsResource = {
170	      groupVersionKind: dnsPolicyGVK,
171	      isList: false,
172	      name: nameEdit,
173	      namespace: namespaceEdit,
174	    };
175	  }
176	
177	  const [dnsData, dnsLoaded, dnsError] = dnsResource
178	    ? useK8sWatchResource(dnsResource)
179	    : [null, false, null]; //Syntax allows for dnsResource to be null in the case of a create
180	
181	  React.useEffect(() => {
182	    if (dnsLoaded && !dnsError) {
183	      if (!Array.isArray(dnsData)) {
184	        const dnsPolicyUpdate = dnsData as dnsPolicyEdit;
185	        setCreationTimestamp(dnsPolicyUpdate.metadata.creationTimestamp);
186	        setResourceVersion(dnsPolicyUpdate.metadata.resourceVersion);
187	        setFormDisabled(true);
188	        setCreate(false);
189	        setPolicyName(dnsPolicyUpdate.metadata?.name || '');
190	        setSelectedGateway({
191	          name: dnsPolicyUpdate.spec?.targetRef?.name || '',
192	          namespace: dnsPolicyUpdate.metadata?.namespace || '',
193	        });
194	        setHealthCheck({
195	          endpoint: dnsPolicyUpdate.spec?.healthCheck?.endpoint || '',
196	          failureThreshold: dnsPolicyUpdate.spec?.healthCheck?.failureThreshold,
197	          port: dnsPolicyUpdate.spec?.healthCheck?.port || null,
198	          protocol: dnsPolicyUpdate.spec?.healthCheck?.protocol || 'HTTP',
199	        });
200	        const providerRef =
201	          Array.isArray(dnsPolicyUpdate.spec?.providerRefs) &&
202	          dnsPolicyUpdate.spec.providerRefs.length > 0
203	            ? dnsPolicyUpdate.spec.providerRefs[0]
204	            : { name: '' };
205	
206	        setProviderRefs([providerRef]);
207	        setLoadBalancing({
208	          geo: dnsPolicyUpdate.spec?.loadBalancing?.geo || '',
209	          weight: dnsPolicyUpdate.spec?.loadBalancing?.weight || 0,
210	          defaultGeo:
211	            dnsPolicyUpdate.spec?.loadBalancing?.defaultGeo !== undefined
212	              ? dnsPolicyUpdate.spec.loadBalancing?.defaultGeo
213	              : false, // Default to false if not present
214	        });
215	
216	        console.log('Initializing dns with existing dns for update');
217	      }
218	    } else if (dnsError) {
219	      console.error('Failed to fetch the resource:', dnsError);
220	    }
221	  }, [dnsData, dnsLoaded, dnsError]);
222	
223	  const handleYAMLChange = (yamlInput: string) => {
224	    try {
225	      const parsedYaml = yaml.load(yamlInput);
226	      setPolicyName(parsedYaml.metadata?.name || '');
227	      setSelectedGateway({
228	        name: parsedYaml.spec?.targetRef?.name || '',
229	        namespace: parsedYaml.metadata?.namespace || '',
230	      });
231	      setHealthCheck({
232	        endpoint: parsedYaml.spec?.healthCheck?.endpoint || '',
233	        failureThreshold: parsedYaml.spec?.healthCheck?.failureThreshold,
234	        port: parsedYaml.spec?.healthCheck?.port || '',
235	        protocol: parsedYaml.spec?.healthCheck?.protocol || '',
236	      });
237	      const providerRef =
238	        Array.isArray(parsedYaml.spec?.providerRefs) && parsedYaml.spec.providerRefs.length > 0
239	          ? parsedYaml.spec.providerRefs[0]
240	          : { name: '' };
241	
242	      setProviderRefs([providerRef]);
243	
244	      setLoadBalancing({
245	        geo: parsedYaml.spec?.loadBalancing?.geo || '',
246	        weight: parsedYaml.spec?.loadBalancing?.weight || '',
247	        defaultGeo:
248	          parsedYaml.spec?.loadBalancing?.defaultGeo !== undefined
