267	
268	  const handleCancelResource = () => {
269	    handleCancel(selectedNamespace, dnsPolicy, history);
270	  };
271	  const formValidation = () => {
272	    if (
273	      policyName &&
274	      selectedGateway.name &&
275	      providerRefs.length > 0 &&
276	      (!loadBalancingExpanded ||
277	        (loadBalancing.geo && loadBalancing.weight && loadBalancing.defaultGeo !== '')) &&
278	      (!healthExpanded ||
279	        (healthCheck.endpoint &&
280	          healthCheck.failureThreshold > 0 &&
281	          healthCheck.port > 0 &&
282	          healthCheck.protocol !== ''))
283	    ) {
284	      isFormValid = true;
285	    }
286	    return isFormValid;
287	  };
288	
289	  return (
290	    <>
291	      <Helmet>
292	        <title data-test="example-page-title">
293	          {create ? t('Create DNS Policy') : t('Edit DNS Policy')}
294	        </title>
295	      </Helmet>
296	      <PageSection variant="light" className="pf-m-no-padding">
297	        <div className="co-m-nav-title">
298	          <Title headingLevel="h1">{create ? t('Create DNS Policy') : t('Edit DNS Policy')}</Title>
299	          <p className="help-block co-m-pane__heading-help-text">
300	            <div>
301	              {t(
302	                'DNSPolicy configures how North-South based traffic should be balanced and reach the gateways',
303	              )}
304	            </div>
305	          </p>
306	        </div>
307	        <FormGroup
308	          className="kuadrant-editor-toggle"
309	          role="radiogroup"
310	          isInline
311	          hasNoPaddingTop
312	          fieldId="create-type-radio-group"
313	          label="Create via:"
314	        >
315	          <Radio
316	            name="create-type-radio"
317	            label="Form"
318	            id="create-type-radio-form"
319	            isChecked={createView === 'form'}
320	            onChange={() => setCreateView('form')}
321	          />
322	          <Radio
323	            name="create-type-radio"
324	            label="YAML"
325	            id="create-type-radio-yaml"
326	            isChecked={createView === 'yaml'}
327	            onChange={() => setCreateView('yaml')}
328	          />
329	        </FormGroup>
330	      </PageSection>
331	      {createView === 'form' ? (
332	        <PageSection variant="light">
333	          <Form className="co-m-pane__form">
334	            <FormGroup label={t('Policy Name')} isRequired fieldId="policy-name">
335	              <TextInput
336	                isRequired
337	                type="text"
338	                id="policy-name"
339	                name="policy-name"
340	                value={policyName}
341	                onChange={handlePolicyChange}
342	                isDisabled={formDisabled}
343	                placeholder={t('Policy name')}
344	              />
345	              <FormHelperText>
346	                <HelperText>
347	                  <HelperTextItem>{t('Unique name of the DNS Policy')}</HelperTextItem>
348	                </HelperText>
349	              </FormHelperText>
350	            </FormGroup>
351	            <GatewaySelect selectedGateway={selectedGateway} onChange={setSelectedGateway} />
352	            <FormGroup label={t('Provider Ref')} isRequired fieldId="Provider-ref">
353	              <TextInput
354	                isRequired
355	                type="text"
356	                id="provider-ref"
357	                name="provider-ref"
358	                value={providerRefs.length > 0 ? providerRefs[0].name : ''}
359	                onChange={handleProviderRefs}
360	                placeholder={t('Provider Ref')}
361	              />
362	              <FormHelperText>
363	                <HelperText>
364	                  <HelperTextItem>
365	                    {t(
366	                      'Reference to an existing secret resource containing DNS provider credentials and configuration',
367	                    )}
368	                  </HelperTextItem>
369	                </HelperText>
370	              </FormHelperText>
371	            </FormGroup>
372	            <ExpandableSection
373	              toggleText={t('LoadBalancing')}
374	              className="pf-u-mb-0"
375	              isExpanded={loadBalancingExpanded}
376	              onToggle={() => setLoadBalancingExpanded(!loadBalancingExpanded)}
377	            >
378	              <LoadBalancingField
379	                loadBalancing={loadBalancing}
380	                onChange={setLoadBalancing}
381	                formDisabled={formDisabled}
382	              />
383	            </ExpandableSection>
384	            <ExpandableSection
385	              toggleText={t('Health Check')}
386	              className="pf-u-mt-0"
387	              isExpanded={healthExpanded}
388	              onToggle={() => setHealthExpanded(!healthExpanded)}
389	            >
390	              <HealthCheckField healthCheck={healthCheck} onChange={setHealthCheck} />
391	            </ExpandableSection>
392	            <ActionGroup className="pf-u-mt-0">
393	              <KuadrantCreateUpdate
394	                model={dnsPolicyModel}
395	                resource={dnsPolicy}
396	                policyType="dns"
397	                history={history}
398	                validation={formValidation()}
399	              />
400	              <Button variant="link" onClick={handleCancelResource}>
401	                {t('Cancel')}
402	              </Button>
403	            </ActionGroup>
404	          </Form>
405	        </PageSection>
406	      ) : (
407	        <React.Suspense fallback={<div> {t('Loading..')}.</div>}>
408	          <ResourceYAMLEditor
409	            initialResource={yamlInput}
410	            create={create}
411	            onChange={handleYAMLChange}
412	          ></ResourceYAMLEditor>
413	        </React.Suspense>
414	      )}
415	    </>
416	  );
417	};
418	
419	export default KuadrantDNSPolicyCreatePage;

